import { Card, Elevation, H1, H2 } from '@blueprintjs/core';
import { DashboardKPIs, DepotCapacityCards, MaintenanceAlerts } from '@/components/dashboard';

export default function Home() {
  return (
    <div>
      <Card elevation={Elevation.ONE}>
        <H1>MMS Dashboard</H1>
        <p className="bp5-text-muted">
          Railway Fleet Mileage Management System - Demo Version
        </p>
      </Card>

      {/* Fleet Summary KPIs - Story 2.1 */}
      <section>
        <H2>Fleet Overview</H2>
        <DashboardKPIs />
      </section>

      {/* Depot Capacity Cards - Story 2.3 */}
      <section>
        <H2>Depot Capacity</H2>
        <DepotCapacityCards />
      </section>

      {/* Maintenance Alerts - Story 2.4 */}
      <section>
        <H2>Maintenance Alerts</H2>
        <MaintenanceAlerts />
      </section>
    </div>
  );
}

