/**
 * MMS - API Client Utilities
 *
 * Centralized API client for backend communication
 */

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000';

interface ApiResponse<T> {
  data: T | null;
  error: string | null;
}

/**
 * Generic fetch wrapper with error handling
 */
export async function apiFetch<T>(endpoint: string, options?: RequestInit): Promise<ApiResponse<T>> {
  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options?.headers,
      },
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      return {
        data: null,
        error: errorData.error || `API Error: ${response.status}`,
      };
    }

    const data = await response.json();
    return { data, error: null };
  } catch (err) {
    return {
      data: null,
      error: err instanceof Error ? err.message : 'Network error',
    };
  }
}

/**
 * Dashboard API
 */
export interface DashboardSummary {
  totalTrains: number;
  availableTrains: number;
  inMaintenanceCount: number;
  kmVariance: number;
  varianceStatus: 'green' | 'yellow' | 'red';
}

export interface DepotCapacity {
  id: string;
  name: string;
  code: string;
  currentOccupancy: number;
  maxCapacity: number;
  percentUsed: number;
}

export interface DepotCapacityResponse {
  depots: DepotCapacity[];
}

export interface MaintenanceAlert {
  id: string;
  trainId: string;
  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
  date: string;
  depot: string;
  depotCode: string;
  durationDays: number;
}

export interface MaintenanceAlertsResponse {
  totalUpcoming: number;
  countByType: {
    PM1: number;
    PM2: number;
    HM: number;
    OVH: number;
  };
  alerts: MaintenanceAlert[];
}

export const dashboardApi = {
  getSummary: () => apiFetch<DashboardSummary>('/api/dashboard/summary'),
  getDepotCapacity: () => apiFetch<DepotCapacityResponse>('/api/dashboard/depot-capacity'),
  getMaintenanceAlerts: () => apiFetch<MaintenanceAlertsResponse>('/api/dashboard/maintenance-alerts'),
};

/**
 * Trains API
 */
export interface Train {
  id: string;
  trainId: string;
  fleetId: string;
  baseDepotId: string;
  currentKm: number;
  targetKm: number;
  fitnessStatus: 'fit' | 'unfit';
  lastMaintenanceDate: string | null;
  nextMaintenanceKm: number | null;
  latitude: string | null;
  longitude: string | null;
  fleet: {
    id: string;
    name: string;
    manufacturer: string | null;
  } | null;
  baseDepot: {
    id: string;
    name: string;
    code: string;
    latitude: string | null;
    longitude: string | null;
  } | null;
  deltaFromAverage: number;
  deltaPercent: number;
}

export interface TrainsResponse {
  trains: Train[];
}

export interface Depot {
  id: string;
  name: string;
  code: string;
  latitude: string | null;
  longitude: string | null;
  capacityTracks: number;
  capacityManhours: number;
}

export interface DepotsResponse {
  depots: Depot[];
}

export const trainsApi = {
  getAll: (params?: { status?: string; depot?: string }) => {
    const query = new URLSearchParams();
    if (params?.status) query.set('status', params.status);
    if (params?.depot) query.set('depot', params.depot);
    const queryStr = query.toString();
    return apiFetch<TrainsResponse>(`/api/trains${queryStr ? `?${queryStr}` : ''}`);
  },
  getById: (id: string) => apiFetch<Train>(`/api/trains/${id}`),
};

export const depotsApi = {
  getAll: () => apiFetch<DepotsResponse>('/api/depots'),
};

/**
 * Services API
 */
export interface Service {
  id: string;
  serviceCode: string;
  origin: string;
  destination: string;
  distanceKm: number;
  departureTime: string;
  arrivalTime: string;
  serviceType: string;
}

export interface PendingServicesResponse {
  date: string;
  services: Service[];
}

export const servicesApi = {
  getPending: (date?: string) => {
    const query = date ? `?date=${date}` : '';
    return apiFetch<PendingServicesResponse>(`/api/services/pending${query}`);
  },
};

/**
 * Allocations API
 */
export interface Recommendation {
  trainId: string;
  train_id: string;
  score: number;
  justifications: string[];
  deadRunningKm: number;
}

export interface RecommendationsResponse {
  recommendations: Recommendation[];
  solverTimeMs: number;
  fallback?: boolean;
}

export interface Allocation {
  id: string;
  serviceId: string;
  trainId: string;
  allocationDate: string;
  status: string;
  score: number | null;
  justifications: string[] | null;
}

export interface AllocationResponse {
  allocation: Allocation;
}

export const allocationsApi = {
  recommend: (serviceId: string, date: string) =>
    apiFetch<RecommendationsResponse>('/api/allocations/recommend', {
      method: 'POST',
      body: JSON.stringify({ serviceId, date }),
    }),
  create: (serviceId: string, trainId: string, date: string, score?: number, justifications?: string[]) =>
    apiFetch<AllocationResponse>('/api/allocations', {
      method: 'POST',
      body: JSON.stringify({ serviceId, trainId, date, score, justifications }),
    }),
};

// Helper function for POST requests
async function apiFetchWithBody<T>(endpoint: string, options: RequestInit): Promise<ApiResponse<T>> {
  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      return {
        data: null,
        error: errorData.error || `API Error: ${response.status}`,
      };
    }

    const data = await response.json();
    return { data, error: null };
  } catch (err) {
    return {
      data: null,
      error: err instanceof Error ? err.message : 'Network error',
    };
  }
}

'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  Alignment,
  Tag,
  Intent,
  Tooltip,
  Classes,
} from '@blueprintjs/core';
import { useTheme } from './ThemeContext';

const navItems = [
  { href: '/', label: 'Dashboard', icon: 'dashboard' },
  { href: '/map', label: 'Map', icon: 'map' },
  { href: '/allocation', label: 'Allocation', icon: 'th-derived' },
  { href: '/fleet', label: 'Fleet', icon: 'drive-time' },
  { href: '/balancing', label: 'Balancing', icon: 'horizontal-bar-chart' },
  { href: '/schedule', label: 'Schedule', icon: 'timeline-events' },
  { href: '/maintenance', label: 'Maintenance', icon: 'build' },
];

/**
 * Main Navigation Component
 *
 * Provides navigation links to all main pages using Blueprint Navbar.
 * Highlights the current active page.
 * Includes theme toggle button for light/dark mode.
 */
export function Navigation() {
  const pathname = usePathname();
  const { theme, toggleTheme } = useTheme();

  return (
    <Navbar fixedToTop={false}>
      <NavbarGroup align={Alignment.LEFT}>
        <NavbarHeading>
          <Link href="/" style={{ textDecoration: 'none', color: 'inherit' }}>
            <strong>MMS</strong>
            <span className={Classes.TEXT_MUTED} style={{ marginLeft: 8, fontSize: 12 }}>
              Metro Mileage Management
            </span>
          </Link>
        </NavbarHeading>
        <NavbarDivider />
        {navItems.map((item) => {
          const isActive = pathname === item.href ||
            (item.href !== '/' && pathname.startsWith(item.href));

          return (
            <Link key={item.href} href={item.href} style={{ textDecoration: 'none' }}>
              <Button
                minimal={!isActive}
                intent={isActive ? Intent.PRIMARY : Intent.NONE}
                text={item.label}
                icon={item.icon as any}
              />
            </Link>
          );
        })}
      </NavbarGroup>

      <NavbarGroup align={Alignment.RIGHT}>
        <Tooltip content={theme === 'light' ? 'Switch to Dark Mode' : 'Switch to Light Mode'}>
          <Button
            minimal
            icon={theme === 'light' ? 'moon' : 'flash'}
            onClick={toggleTheme}
            aria-label={theme === 'light' ? 'Switch to Dark Mode' : 'Switch to Light Mode'}
          />
        </Tooltip>
        <NavbarDivider />
        <Tag intent={Intent.WARNING} minimal>DEMO</Tag>
      </NavbarGroup>
    </Navbar>
  );
}

/**
 * Fleet List Page
 *
 * Displays list of trains with filtering capabilities.
 * Can be filtered by status (fit/unfit) or depot.
 */

import { Card, Elevation, Tag, Intent, H1, Classes, Callout } from '@blueprintjs/core';

interface FleetPageProps {
  searchParams: Promise<{ status?: string; depot?: string }>;
}

export default async function FleetPage({ searchParams }: FleetPageProps) {
  const params = await searchParams;
  const { status, depot } = params;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      <Card elevation={Elevation.ONE}>
        <H1>Fleet Overview</H1>
        <p className={Classes.TEXT_MUTED}>
          Train list with status and mileage information
        </p>
      </Card>

      {/* Filter Indicators */}
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
        {status && (
          <Tag intent={Intent.PRIMARY} round>
            Filter: Status = {status}
          </Tag>
        )}
        {depot && (
          <Tag intent={Intent.NONE} round>
            Filter: Depot = {depot}
          </Tag>
        )}
      </div>

      {/* Placeholder for train list - Epic 3 */}
      <Callout intent={Intent.NONE} icon="info-sign">
        <p className={Classes.TEXT_MUTED} style={{ marginBottom: 8 }}>
          Train list will be implemented in Epic 3
        </p>
        <p className={Classes.TEXT_SMALL}>
          Showing trains with filters: {JSON.stringify({ status, depot })}
        </p>
      </Callout>
    </div>
  );
}

/**
 * Allocation Page
 *
 * Main interface for train-to-service allocation.
 * Enables dispatchers to view pending services and assign trains
 * using AI-powered recommendations with visible justifications.
 */

import { Card, Elevation, H1, Classes } from '@blueprintjs/core';
import { AllocationPanel } from '@/components/allocation';

export default function AllocationPage() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      <Card elevation={Elevation.ONE}>
        <H1>Train Allocation</H1>
        <p className={Classes.TEXT_MUTED}>
          Assign trains to services using AI-powered recommendations optimized for mileage balancing
        </p>
      </Card>

      <AllocationPanel />
    </div>
  );
}

/**
 * Km Balancing Page
 *
 * Displays mileage distribution, variance analysis, and simulation tools.
 * Shows histogram, train ranking by delta, and what-if scenarios.
 */

import { Card, Elevation, H1, Classes } from '@blueprintjs/core';
import { BalancingDashboard, SimulationPanel } from '@/components/balancing';

export default function BalancingPage() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      <Card elevation={Elevation.ONE}>
        <H1>Km Balancing</H1>
        <p className={Classes.TEXT_MUTED}>
          Analyze mileage distribution, identify balancing opportunities, and run what-if simulations
        </p>
      </Card>

      {/* Distribution and Ranking Dashboard */}
      <BalancingDashboard />

      {/* What-If Simulation Panel */}
      <SimulationPanel />
    </div>
  );
}

/**
 * Maintenance Gantt Page
 *
 * Displays maintenance schedule in a timeline/Gantt view.
 * Shows PM1/PM2/HM/OVH events across trains and depots.
 * Supports drag-drop scheduling and real-time constraint validation.
 */

import { Card, Elevation, H1, Classes } from '@blueprintjs/core';
import { MaintenanceGantt, DepotCapacityHeatmap } from '@/components/maintenance';

export default function MaintenancePage() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      <Card elevation={Elevation.ONE}>
        <H1>Maintenance Schedule</H1>
        <p className={Classes.TEXT_MUTED}>
          4-week timeline view with drag-and-drop scheduling and depot capacity monitoring
        </p>
      </Card>

      {/* Gantt Chart */}
      <MaintenanceGantt />

      {/* Depot Capacity Heatmap */}
      <DepotCapacityHeatmap />
    </div>
  );
}

