    20→  const [summary, setSummary] = useState<DashboardSummary | null>(null);
    21→  const [loading, setLoading] = useState(true);
    22→  const [error, setError] = useState<string | null>(null);
    23→
    24→  useEffect(() => {
    25→    async function fetchSummary() {
    26→      setLoading(true);
    27→      const { data, error } = await dashboardApi.getSummary();
    28→
    29→      if (error) {
    30→        setError(error);
    31→      } else if (data) {
    32→        setSummary(data);
    33→      }
    34→      setLoading(false);
    35→    }
    36→
    37→    fetchSummary();
    38→  }, []);
    39→
    40→  // Determine variance config based on status
    41→  const getVarianceConfig = (status?: 'green' | 'yellow' | 'red'): {
    42→    icon: IconName;
    43→    subtitle: string;
    44→  } => {
    45→    switch (status) {
    46→      case 'green':
    47→        return {
    48→          icon: 'tick-circle',
    49→          subtitle: 'Target met',
    50→        };
    51→      case 'yellow':
    52→        return {
    53→          icon: 'warning-sign',
