    55→        };
    56→      case 'red':
    57→        return {
    58→          icon: 'error',
    59→          subtitle: 'Critical variance',
    60→        };
    61→      default:
    62→        return {
    63→          icon: 'pulse',
    64→          subtitle: '',
    65→        };
    66→    }
    67→  };
    68→
    69→  // Calculate available percentage
    70→  const availablePercentage = summary
    71→    ? Math.round((summary.availableTrains / summary.totalTrains) * 100)
    72→    : 0;
    73→
    74→  const varianceConfig = getVarianceConfig(summary?.varianceStatus);
    75→
    76→  if (error) {
    77→    return (
    78→      <Callout intent={Intent.DANGER} title="Error loading dashboard">
