    81→          Make sure the API server is running at <code>http://localhost:4000</code>
    82→        </p>
    83→      </Callout>
    84→    );
    85→  }
    86→
    87→  // Navigation handlers
    88→  const handleNavigateFleet = () => router.push('/fleet');
    89→  const handleNavigateAvailable = () => router.push('/fleet?status=fit');
    90→  const handleNavigateMaintenance = () => router.push('/maintenance');
    91→  const handleNavigateBalancing = () => router.push('/balancing');
    92→
    93→  return (
    94→    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16 }}>
    95→      <KPICard
    96→        title="Total Trains"
    97→        value={summary?.totalTrains ?? '--'}
    98→        icon="drive-time"
    99→        loading={loading}
   100→        onClick={handleNavigateFleet}
