   106→        subtitle={summary ? `${availablePercentage}% of fleet` : undefined}
   107→        icon="tick-circle"
   108→        loading={loading}
   109→        onClick={handleNavigateAvailable}
   110→        tooltip="Click to view available trains"
   111→      />
   112→      <KPICard
   113→        title="In Maintenance"
   114→        value={summary?.inMaintenanceCount ?? '--'}
   115→        icon="build"
   116→        loading={loading}
   117→        onClick={handleNavigateMaintenance}
   118→        tooltip="Click to view maintenance schedule"
   119→      />
   120→      <KPICard
   121→        title="Km Variance"
   122→        value={summary ? `${summary.kmVariance}%` : '--%'}
   123→        subtitle={varianceConfig.subtitle}
   124→        icon={varianceConfig.icon}
   125→        tooltip={summary ? `Fleet mileage variance: ${summary.kmVariance}% (target: ≤10%) - Click for details` : undefined}
   126→        loading={loading}
   127→        onClick={handleNavigateBalancing}
   128→      />
   129→    </div>
   130→  );
   131→}
