'use client';

import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
  Elevation,
  Button,
  Spinner,
  Callout,
  Intent,
  Tag,
  Icon,
  InputGroup,
  H2,
  Classes,
} from '@blueprintjs/core';
import {
  servicesApi,
  allocationsApi,
  Service,
  Recommendation,
} from '@/lib/api';

interface AllocationPanelProps {
  onAllocationComplete?: () => void;
}

/**
 * Allocation Panel Component
 *
 * Main component for train-to-service allocation:
 * - Lists pending services
 * - Generates recommendations
 * - Displays justifications
 * - Confirms allocations
 */
export function AllocationPanel({ onAllocationComplete }: AllocationPanelProps) {
  const [services, setServices] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<Service | null>(null);
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loading, setLoading] = useState(true);
  const [recommending, setRecommending] = useState(false);
  const [allocating, setAllocating] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [selectedDate, setSelectedDate] = useState(
    new Date().toISOString().split('T')[0]
  );
  const [isFallback, setIsFallback] = useState(false);
  const [solverTime, setSolverTime] = useState(0);

  const fetchServices = useCallback(async () => {
    setLoading(true);
    setError(null);
    const { data, error } = await servicesApi.getPending(selectedDate);

    if (error) {
      setError(error);
    } else if (data) {
      setServices(data.services);
    }
    setLoading(false);
  }, [selectedDate]);

  useEffect(() => {
    fetchServices();
  }, [fetchServices]);

  const handleSelectService = (service: Service) => {
    setSelectedService(service);
    setRecommendations([]);
    setSuccessMessage(null);
  };

  const handleGetRecommendations = async () => {
    if (!selectedService) return;

    setRecommending(true);
    setError(null);

    const { data, error } = await allocationsApi.recommend(
      selectedService.id,
      selectedDate
    );

    if (error) {
      setError(error);
    } else if (data) {
      setRecommendations(data.recommendations);
      setIsFallback(data.fallback || false);
      setSolverTime(data.solverTimeMs);
    }
    setRecommending(false);
  };

  const handleAllocate = async (rec: Recommendation) => {
    if (!selectedService) return;

    setAllocating(rec.trainId);
    setError(null);

    const { data, error } = await allocationsApi.create(
      selectedService.id,
      rec.trainId,
      selectedDate,
      rec.score,
      rec.justifications
    );

    if (error) {
      setError(error);
    } else if (data) {
      setSuccessMessage(
        `Train ${rec.train_id} assigned to ${selectedService.serviceCode}`
      );
      // Remove allocated service from list
      setServices((prev) =>
        prev.filter((s) => s.id !== selectedService.id)
      );
      setSelectedService(null);
      setRecommendations([]);
      onAllocationComplete?.();
    }
    setAllocating(null);
  };

  const formatTime = (time: string | undefined) => {
    if (!time) return '--:--';
    return time.substring(0, 5);
  };

  return (
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
      {/* Left Panel - Pending Services */}
      <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
        <div style={{ padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <H2 style={{ margin: 0 }}>Pending Services</H2>
            <InputGroup
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              style={{ width: 140 }}
            />
          </div>
          <p className={Classes.TEXT_MUTED} style={{ margin: '8px 0 0' }}>
            {services.length} services awaiting allocation
          </p>
        </div>

        {loading ? (
          <div style={{ padding: 32, textAlign: 'center' }}>
            <Spinner size={32} />
            <p className={Classes.TEXT_MUTED} style={{ marginTop: 8 }}>Loading services...</p>
          </div>
        ) : services.length === 0 ? (
          <div style={{ padding: 32, textAlign: 'center' }} className={Classes.TEXT_MUTED}>
            No pending services for {selectedDate}
          </div>
        ) : (
          <div style={{ maxHeight: 500, overflowY: 'auto' }}>
            {services.map((service) => (
              <div
                key={service.id}
                style={{
                  padding: 16,
                  cursor: 'pointer',
                  borderLeft: selectedService?.id === service.id ? '4px solid #2b95d6' : '4px solid transparent',
                  backgroundColor: selectedService?.id === service.id ? 'rgba(43, 149, 214, 0.1)' : 'transparent',
                }}
                onClick={() => handleSelectService(service)}
              >
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                  <span style={{ fontWeight: 600, fontFamily: 'monospace' }}>
                    {service.serviceCode}
                  </span>
                  <span className={Classes.TEXT_MUTED}>
                    {formatTime(service.departureTime)}
                  </span>
                </div>
                <div className={Classes.TEXT_MUTED} style={{ marginTop: 4 }}>
                  {service.origin} → {service.destination}
                </div>
                <div style={{ marginTop: 4, display: 'flex', alignItems: 'center', gap: 16 }}>
                  <Tag minimal>{service.distanceKm} km</Tag>
                  <Tag minimal intent={Intent.NONE}>{service.serviceType}</Tag>
                </div>
              </div>
            ))}
          </div>
        )}
      </Card>

      {/* Right Panel - Recommendations */}
      <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
        <div style={{ padding: 16 }}>
          <H2 style={{ margin: 0 }}>Train Recommendations</H2>
          {selectedService && (
            <p className={Classes.TEXT_MUTED} style={{ margin: '8px 0 0' }}>
              For {selectedService.serviceCode}: {selectedService.origin} → {selectedService.destination}
            </p>
          )}
        </div>

        {/* Success Message */}
        {successMessage && (
          <Callout intent={Intent.SUCCESS} icon="tick-circle" style={{ margin: 16 }}>
            {successMessage}
          </Callout>
        )}

        {/* Error Message */}
        {error && (
          <Callout intent={Intent.DANGER} style={{ margin: 16 }}>
            {error}
          </Callout>
        )}

        {!selectedService ? (
          <div style={{ padding: 32, textAlign: 'center' }} className={Classes.TEXT_MUTED}>
            Select a service to get train recommendations
          </div>
        ) : recommendations.length === 0 ? (
          <div style={{ padding: 32, textAlign: 'center' }}>
            <Button
              onClick={handleGetRecommendations}
              disabled={recommending}
              intent={Intent.PRIMARY}
              large
              icon={recommending ? undefined : 'lightbulb'}
              loading={recommending}
            >
              {recommending ? 'Analyzing...' : 'Get Recommendations'}
            </Button>
            <p className={Classes.TEXT_MUTED} style={{ marginTop: 8 }}>
              AI-powered recommendations based on km balancing
            </p>
          </div>
        ) : (
          <div>
            {/* Solver Info */}
            {isFallback && (
              <Callout intent={Intent.WARNING} icon="warning-sign" style={{ margin: 16 }}>
                Using fallback ranking (solver unavailable)
              </Callout>
            )}
            {solverTime > 0 && (
              <div className={Classes.TEXT_MUTED} style={{ padding: 8, textAlign: 'right', fontSize: 12 }}>
                Solver time: {solverTime}ms
              </div>
            )}

            {/* Recommendations List */}
            <div>
              {recommendations.map((rec, idx) => (
                <div key={rec.trainId} style={{ padding: 16, borderTop: idx > 0 ? '1px solid rgba(128, 128, 128, 0.2)' : 'none' }}>
                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{ fontWeight: 600, fontFamily: 'monospace' }}>
                        {rec.train_id}
                      </span>
                      <Tag intent={Intent.PRIMARY} minimal>Score: {rec.score}</Tag>
                      {idx === 0 && (
                        <Tag intent={Intent.SUCCESS}>Best Match</Tag>
                      )}
                    </div>
                    <Button
                      onClick={() => handleAllocate(rec)}
                      disabled={allocating !== null}
                      intent={Intent.SUCCESS}
                      loading={allocating === rec.trainId}
                      small
                    >
                      Assign
                    </Button>
                  </div>

                  <div className={Classes.TEXT_MUTED} style={{ marginTop: 8 }}>
                    Dead running: {rec.deadRunningKm} km
                  </div>

                  {/* Justifications */}
                  <div style={{ marginTop: 8 }}>
                    {rec.justifications.map((j, jIdx) => (
                      <div
                        key={jIdx}
                        className={Classes.TEXT_MUTED}
                        style={{ display: 'flex', alignItems: 'flex-start', gap: 8, marginTop: 4 }}
                      >
                        <Icon icon="tick" intent={Intent.SUCCESS} size={14} />
                        <span>{j}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </Card>
    </div>
  );
}

