    16→  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
    17→  startDate: Date;
    18→  endDate: Date;
    19→  depot: string;
    20→}
    21→
    22→interface ScheduleCanvasProps {
    23→  events: MaintenanceEvent[];
    24→  onEventSelect?: (event: MaintenanceEvent) => void;
    25→  onEventHover?: (event: MaintenanceEvent | null) => void;
    26→  startDate?: Date;
    27→  endDate?: Date;
    28→  width?: number;
    29→  height?: number;
    30→}
    31→
    32→// Color palette for maintenance types
    33→const MAINTENANCE_COLORS = {
    34→  PM1: 0x10B981, // Green
    35→  PM2: 0x3B82F6, // Blue
    36→  HM: 0xF59E0B,  // Amber
    37→  OVH: 0xEF4444, // Red
    38→};
    39→
    40→// LOD level descriptions
    41→const LOD_LABELS = {
    42→  0: 'Strategic (10-12 years)',
    43→  1: 'Tactical (1-3 years)',
    44→  2: 'Operational (1-6 months)',
    45→  3: 'Execution (1-4 weeks)',
    46→};
    47→
    48→// Day width in pixels at scale 1.0
    49→const DAY_WIDTH = 20;
    50→const ROW_HEIGHT = 40;
    51→const HEADER_HEIGHT = 60;
    52→
    53→export function ScheduleCanvas({
    54→  events,
    55→  onEventSelect,
    56→  onEventHover,
    57→  startDate = new Date(),
    58→  endDate = new Date(Date.now() + 365 * 24 * 60 * 60 * 1000),
    59→  width = 1200,
    60→  height = 600,
    61→}: ScheduleCanvasProps) {
    62→  const containerRef = useRef<HTMLDivElement>(null);
    63→  const appRef = useRef<Application | null>(null);
    64→  const viewportRef = useRef<Viewport | null>(null);
    65→
    66→  // Use local state for LOD and scale to avoid toolkit infinite loop issue
    67→  const [currentLOD, setCurrentLOD] = useState<LODLevel>(2);
    68→  const [scale, setScale] = useState(0.5);
    69→
    70→  // Initialize Pixi application
    71→  useEffect(() => {
    72→    if (!containerRef.current) return;
    73→
    74→    const app = new Application();
    75→
    76→    const initApp = async () => {
    77→      await app.init({
    78→        width,
    79→        height,
    80→        backgroundColor: 0x0A0A0A, // Dark canvas background
    81→        resolution: window.devicePixelRatio || 1,
    82→        autoDensity: true,
    83→        antialias: true,
    84→      });
    85→
    86→      containerRef.current?.appendChild(app.canvas);
    87→      appRef.current = app;
    88→
    89→      // Create viewport
    90→      const viewport = new Viewport({
    91→        screenWidth: width,
    92→        screenHeight: height,
    93→        worldWidth: width * 10,
    94→        worldHeight: height * 5,
    95→        events: app.renderer.events,
    96→      });
    97→
    98→      app.stage.addChild(viewport);
    99→      viewportRef.current = viewport;
   100→
   101→      // Enable viewport interactions
   102→      viewport
   103→        .drag()
   104→        .pinch()
   105→        .wheel()
   106→        .decelerate()
   107→        .clampZoom({
   108→          minScale: 0.05,
   109→          maxScale: 4.0,
   110→        });
   111→
   112→      // Listen to zoom/scale changes - update local state
   113→      viewport.on('zoomed', () => {
   114→        const newScale = viewport.scale.x;
   115→        setScale(newScale);
   116→        setCurrentLOD(getLODFromScale(newScale));
   117→      });
   118→
   119→      viewport.on('moved', () => {
   120→        // Position tracking handled by viewport internally
   121→      });
   122→
   123→      // Initial render
   124→      renderContent(viewport, events, startDate, endDate, getLODFromScale(0.5));
   125→    };
   126→
   127→    initApp();
   128→
   129→    return () => {
   130→      if (appRef.current) {
   131→        appRef.current.destroy(true);
   132→        appRef.current = null;
   133→      }
   134→    };
   135→  }, [width, height]);
   136→
   137→  // Re-render when events or LOD changes
   138→  useEffect(() => {
   139→    if (viewportRef.current) {
   140→      renderContent(viewportRef.current, events, startDate, endDate, currentLOD);
   141→    }
   142→  }, [events, currentLOD, startDate, endDate]);
   143→
   144→  // Handle window resize
   145→  useEffect(() => {
   146→    const handleResize = () => {
   147→      if (appRef.current && viewportRef.current) {
   148→        appRef.current.renderer.resize(width, height);
   149→        viewportRef.current.resize(width, height);
   150→      }
   151→    };
   152→
   153→    window.addEventListener('resize', handleResize);
   154→    return () => window.removeEventListener('resize', handleResize);
   155→  }, [width, height]);
   156→
   157→  const renderContent = useCallback(
   158→    (
   159→      viewport: Viewport,
   160→      events: MaintenanceEvent[],
   161→      startDate: Date,
   162→      endDate: Date,
   163→      lod: LODLevel
   164→    ) => {
   165→      // Clear existing children except the viewport container
   166→      viewport.removeChildren();
   167→
   168→      // Create container for all content
   169→      const contentContainer = new Container();
   170→      viewport.addChild(contentContainer);
   171→
   172→      // Render based on LOD level
   173→      switch (lod) {
   174→        case 0:
   175→          renderStrategicView(contentContainer, events, startDate, endDate);
   176→          break;
   177→        case 1:
   178→          renderTacticalView(contentContainer, events, startDate, endDate);
   179→          break;
   180→        case 2:
   181→          renderOperationalView(contentContainer, events, startDate, endDate);
   182→          break;
   183→        case 3:
   184→          renderExecutionView(contentContainer, events, startDate, endDate, onEventSelect, onEventHover);
   185→          break;
   186→      }
   187→
   188→      // Add timeline ruler
   189→      renderTimelineRuler(contentContainer, startDate, endDate, lod);
   190→    },
   191→    [onEventSelect, onEventHover]
   192→  );
   193→
   194→  return (
   195→    <div style={{ position: 'relative' }}>
   196→      {/* Canvas container */}
   197→      <div ref={containerRef} style={{ borderRadius: 4, overflow: 'hidden' }} />
   198→
   199→      {/* Overlay controls */}
   200→      <Card
   201→        elevation={Elevation.TWO}
   202→        style={{
   203→          position: 'absolute',
   204→          top: 16,
   205→          left: 16,
   206→          padding: 12,
   207→        }}
   208→      >
   209→        <div className={Classes.TEXT_MUTED} style={{ fontSize: 12, marginBottom: 4 }}>LOD Level</div>
   210→        <div style={{ fontWeight: 600 }}>
   211→          {LOD_LABELS[currentLOD as keyof typeof LOD_LABELS]}
   212→        </div>
   213→        <div className={Classes.TEXT_MUTED} style={{ fontSize: 12, marginTop: 4 }}>
   214→          Scale: {(scale * 100).toFixed(0)}%
   215→        </div>
   216→      </Card>
   217→
   218→      {/* Zoom controls */}
   219→      <div style={{ position: 'absolute', bottom: 16, right: 16, display: 'flex', gap: 8 }}>
   220→        <Button
   221→          onClick={() => viewportRef.current?.zoomPercent(0.2, true)}
   222→          style={{ minWidth: 36 }}
   223→        >
   224→          +
   225→        </Button>
   226→        <Button
   227→          onClick={() => viewportRef.current?.zoomPercent(-0.2, true)}
   228→          style={{ minWidth: 36 }}
   229→        >
   230→          -
   231→        </Button>
   232→        <Button
   233→          small
   234→          onClick={() => {
   235→            viewportRef.current?.fit();
   236→            viewportRef.current?.moveCenter(width / 2, height / 2);
   237→          }}
   238→        >
   239→          Fit
   240→        </Button>
   241→      </div>
   242→    </div>
   243→  );
   244→}
   245→
   246→// LOD 0: Strategic View (10-12 years) - Heatmap aggregation
   247→function renderStrategicView(
   248→  container: Container,
   249→  events: MaintenanceEvent[],
   250→  startDate: Date,
   251→  endDate: Date
   252→) {
   253→  const graphics = new Graphics();
   254→  container.addChild(graphics);
   255→
   256→  // Calculate yearly aggregations
   257→  const yearlyData = new Map<number, { PM1: number; PM2: number; HM: number; OVH: number }>();
   258→
   259→  events.forEach((event) => {
   260→    const year = event.startDate.getFullYear();
   261→    if (!yearlyData.has(year)) {
   262→      yearlyData.set(year, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
   263→    }
   264→    const data = yearlyData.get(year)!;
   265→    data[event.type]++;
   266→  });
   267→
   268→  // Render yearly blocks
   269→  const years = Array.from(yearlyData.keys()).sort();
   270→  const blockWidth = 100;
   271→  const blockHeight = 80;
   272→
   273→  years.forEach((year, index) => {
   274→    const data = yearlyData.get(year)!;
   275→    const total = data.PM1 + data.PM2 + data.HM + data.OVH;
   276→    const intensity = Math.min(1, total / 50); // Normalize
   277→
   278→    graphics.rect(
   279→      index * (blockWidth + 10) + 20,
   280→      HEADER_HEIGHT,
   281→      blockWidth,
   282→      blockHeight
   283→    );
   284→    graphics.fill({ color: 0x3B82F6, alpha: 0.3 + intensity * 0.7 });
   285→
   286→    // Year label
   287→    const style = new TextStyle({
   288→      fontSize: 14,
   289→      fill: 0xFAFAFA,
   290→      fontFamily: 'Inter',
   291→    });
   292→    const yearText = new Text({ text: year.toString(), style });
   293→    yearText.x = index * (blockWidth + 10) + 20 + blockWidth / 2 - yearText.width / 2;
   294→    yearText.y = HEADER_HEIGHT + blockHeight + 5;
   295→    container.addChild(yearText);
   296→
   297→    // Count label
   298→    const countStyle = new TextStyle({
   299→      fontSize: 20,
   300→      fill: 0xFAFAFA,
   301→      fontWeight: 'bold',
   302→      fontFamily: 'Inter',
   303→    });
   304→    const countText = new Text({ text: total.toString(), style: countStyle });
   305→    countText.x = index * (blockWidth + 10) + 20 + blockWidth / 2 - countText.width / 2;
   306→    countText.y = HEADER_HEIGHT + blockHeight / 2 - countText.height / 2;
   307→    container.addChild(countText);
   308→  });
   309→}
   310→
   311→// LOD 1: Tactical View (1-3 years) - Campaign bars
   312→function renderTacticalView(
   313→  container: Container,
   314→  events: MaintenanceEvent[],
   315→  startDate: Date,
   316→  endDate: Date
   317→) {
   318→  const graphics = new Graphics();
   319→  container.addChild(graphics);
   320→
   321→  // Calculate quarterly aggregations
   322→  const quarterlyData = new Map<string, { PM1: number; PM2: number; HM: number; OVH: number }>();
   323→
   324→  events.forEach((event) => {
   325→    const year = event.startDate.getFullYear();
   326→    const quarter = Math.floor(event.startDate.getMonth() / 3) + 1;
   327→    const key = `${year}-Q${quarter}`;
   328→
   329→    if (!quarterlyData.has(key)) {
   330→      quarterlyData.set(key, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
   331→    }
   332→    const data = quarterlyData.get(key)!;
   333→    data[event.type]++;
   334→  });
   335→
   336→  // Render quarterly bars
   337→  const quarters = Array.from(quarterlyData.keys()).sort();
   338→  const barWidth = 60;
   339→  const maxHeight = 150;
   340→
   341→  quarters.forEach((quarter, index) => {
   342→    const data = quarterlyData.get(quarter)!;
   343→    let yOffset = HEADER_HEIGHT;
   344→
   345→    // Stack by type
   346→    (['PM1', 'PM2', 'HM', 'OVH'] as const).forEach((type) => {
   347→      const count = data[type];
   348→      if (count > 0) {
   349→        const height = (count / 20) * maxHeight;
   350→        graphics.rect(
   351→          index * (barWidth + 5) + 20,
   352→          yOffset,
   353→          barWidth,
   354→          height
   355→        );
   356→        graphics.fill({ color: MAINTENANCE_COLORS[type] });
   357→        yOffset += height;
   358→      }
   359→    });
   360→
   361→    // Quarter label
   362→    const style = new TextStyle({
   363→      fontSize: 10,
   364→      fill: 0xA1A1A1,
   365→      fontFamily: 'Inter',
   366→    });
   367→    const text = new Text({ text: quarter, style });
   368→    text.x = index * (barWidth + 5) + 20 + barWidth / 2 - text.width / 2;
   369→    text.y = HEADER_HEIGHT + maxHeight + 5;
   370→    container.addChild(text);
   371→  });
   372→}
   373→
   374→// LOD 2: Operational View (1-6 months) - Work orders as blocks
   375→function renderOperationalView(
   376→  container: Container,
   377→  events: MaintenanceEvent[],
   378→  startDate: Date,
   379→  endDate: Date
   380→) {
   381→  const graphics = new Graphics();
   382→  container.addChild(graphics);
   383→
   384→  // Group by train
   385→  const trainGroups = new Map<string, MaintenanceEvent[]>();
   386→  events.forEach((event) => {
   387→    if (!trainGroups.has(event.trainId)) {
   388→      trainGroups.set(event.trainId, []);
   389→    }
   390→    trainGroups.get(event.trainId)!.push(event);
   391→  });
   392→
   393→  const trains = Array.from(trainGroups.keys()).slice(0, 15); // Limit visible trains
   394→  const startTime = startDate.getTime();
   395→  const msPerDay = 24 * 60 * 60 * 1000;
   396→
   397→  trains.forEach((trainId, rowIndex) => {
   398→    const trainEvents = trainGroups.get(trainId)!;
   399→    const y = HEADER_HEIGHT + rowIndex * ROW_HEIGHT;
   400→
   401→    // Row background
   402→    graphics.rect(0, y, 2000, ROW_HEIGHT - 2);
   403→    graphics.fill({ color: rowIndex % 2 === 0 ? 0x141414 : 0x1C1C1C });
   404→
   405→    // Train label
   406→    const style = new TextStyle({
   407→      fontSize: 11,
   408→      fill: 0xA1A1A1,
   409→      fontFamily: 'JetBrains Mono',
   410→    });
   411→    const label = new Text({ text: trainEvents[0]?.trainName || trainId, style });
   412→    label.x = 10;
   413→    label.y = y + ROW_HEIGHT / 2 - label.height / 2;
   414→    container.addChild(label);
   415→
   416→    // Events
   417→    trainEvents.forEach((event) => {
   418→      const startOffset = (event.startDate.getTime() - startTime) / msPerDay;
   419→      const duration = (event.endDate.getTime() - event.startDate.getTime()) / msPerDay;
   420→
   421→      const x = 120 + startOffset * DAY_WIDTH;
   422→      const width = Math.max(duration * DAY_WIDTH, 8);
   423→
   424→      graphics.rect(x, y + 4, width, ROW_HEIGHT - 8);
   425→      graphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   426→    });
   427→  });
   428→}
   429→
   430→// LOD 3: Execution View (1-4 weeks) - Full task details
   431→function renderExecutionView(
   432→  container: Container,
   433→  events: MaintenanceEvent[],
   434→  startDate: Date,
   435→  endDate: Date,
   436→  onEventSelect?: (event: MaintenanceEvent) => void,
   437→  onEventHover?: (event: MaintenanceEvent | null) => void
   438→) {
   439→  const graphics = new Graphics();
   440→  container.addChild(graphics);
   441→
   442→  // Group by train
   443→  const trainGroups = new Map<string, MaintenanceEvent[]>();
   444→  events.forEach((event) => {
   445→    if (!trainGroups.has(event.trainId)) {
   446→      trainGroups.set(event.trainId, []);
   447→    }
   448→    trainGroups.get(event.trainId)!.push(event);
   449→  });
   450→
   451→  const trains = Array.from(trainGroups.keys()).slice(0, 20);
   452→  const startTime = startDate.getTime();
   453→  const msPerDay = 24 * 60 * 60 * 1000;
   454→
   455→  trains.forEach((trainId, rowIndex) => {
   456→    const trainEvents = trainGroups.get(trainId)!;
   457→    const y = HEADER_HEIGHT + rowIndex * ROW_HEIGHT;
   458→
   459→    // Row background
   460→    graphics.rect(0, y, 3000, ROW_HEIGHT - 2);
   461→    graphics.fill({ color: rowIndex % 2 === 0 ? 0x141414 : 0x1C1C1C });
   462→
   463→    // Train label
   464→    const style = new TextStyle({
   465→      fontSize: 12,
   466→      fill: 0xFAFAFA,
   467→      fontFamily: 'JetBrains Mono',
   468→    });
   469→    const label = new Text({ text: trainEvents[0]?.trainName || trainId, style });
   470→    label.x = 10;
   471→    label.y = y + ROW_HEIGHT / 2 - label.height / 2;
   472→    container.addChild(label);
   473→
   474→    // Events with full details
   475→    trainEvents.forEach((event) => {
   476→      const startOffset = (event.startDate.getTime() - startTime) / msPerDay;
   477→      const duration = (event.endDate.getTime() - event.startDate.getTime()) / msPerDay;
   478→
   479→      const x = 150 + startOffset * DAY_WIDTH * 2; // Larger scale at execution level
   480→      const width = Math.max(duration * DAY_WIDTH * 2, 30);
   481→
   482→      // Event block
   483→      const eventGraphics = new Graphics();
   484→      eventGraphics.rect(0, 0, width, ROW_HEIGHT - 10);
   485→      eventGraphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   486→
   487→      // Rounded corners simulation
   488→      eventGraphics.rect(0, 0, width, ROW_HEIGHT - 10);
   489→      eventGraphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   490→
   491→      eventGraphics.x = x;
   492→      eventGraphics.y = y + 5;
   493→      eventGraphics.eventMode = 'static';
   494→      eventGraphics.cursor = 'pointer';
   495→
   496→      eventGraphics.on('pointerover', () => {
   497→        eventGraphics.alpha = 0.8;
   498→        onEventHover?.(event);
   499→      });
   500→
   501→      eventGraphics.on('pointerout', () => {
   502→        eventGraphics.alpha = 1;
   503→        onEventHover?.(null);
   504→      });
   505→
   506→      eventGraphics.on('pointertap', () => {
   507→        onEventSelect?.(event);
   508→      });
   509→
   510→      container.addChild(eventGraphics);
   511→
   512→      // Event type label
   513→      if (width > 40) {
   514→        const typeStyle = new TextStyle({
   515→          fontSize: 10,
   516→          fill: 0xFFFFFF,
   517→          fontWeight: 'bold',
   518→          fontFamily: 'Inter',
   519→        });
   520→        const typeText = new Text({ text: event.type, style: typeStyle });
   521→        typeText.x = x + 5;
   522→        typeText.y = y + 8;
   523→        container.addChild(typeText);
   524→
   525→        // Depot label
   526→        if (width > 80) {
   527→          const depotStyle = new TextStyle({
   528→            fontSize: 9,
   529→            fill: 0xCCCCCC, // Lighter color instead of alpha
   530→            fontFamily: 'Inter',
   531→          });
   532→          const depotText = new Text({ text: event.depot, style: depotStyle });
   533→          depotText.x = x + 5;
   534→          depotText.y = y + 22;
   535→          container.addChild(depotText);
   536→        }
   537→      }
   538→    });
   539→  });
   540→}
   541→
   542→// Timeline ruler
   543→function renderTimelineRuler(
   544→  container: Container,
   545→  startDate: Date,
   546→  endDate: Date,
   547→  lod: LODLevel
   548→) {
   549→  const graphics = new Graphics();
   550→  container.addChild(graphics);
   551→
   552→  // Header background
   553→  graphics.rect(0, 0, 3000, HEADER_HEIGHT);
   554→  graphics.fill({ color: 0x1C1C1C });
   555→
   556→  const style = new TextStyle({
   557→    fontSize: 11,
   558→    fill: 0xA1A1A1,
   559→    fontFamily: 'Inter',
   560→  });
   561→
   562→  // Different granularity based on LOD
   563→  const msPerDay = 24 * 60 * 60 * 1000;
   564→  const startTime = startDate.getTime();
   565→
   566→  if (lod >= 2) {
   567→    // Show months
   568→    const months = [];
   569→    let current = new Date(startDate);
   570→    while (current < endDate) {
   571→      months.push(new Date(current));
   572→      current.setMonth(current.getMonth() + 1);
   573→    }
   574→
   575→    months.forEach((month, index) => {
   576→      const offset = (month.getTime() - startTime) / msPerDay;
   577→      const x = 150 + offset * DAY_WIDTH * (lod === 3 ? 2 : 1);
   578→
   579→      // Month line
   580→      graphics.moveTo(x, HEADER_HEIGHT - 20);
   581→      graphics.lineTo(x, HEADER_HEIGHT);
   582→      graphics.stroke({ color: 0x2A2A2A, width: 1 });
   583→
   584→      // Month label
   585→      const monthLabel = month.toLocaleDateString('en-US', {
   586→        month: 'short',
   587→        year: '2-digit',
   588→      });
   589→      const text = new Text({ text: monthLabel, style });
   590→      text.x = x + 5;
   591→      text.y = HEADER_HEIGHT - 18;
   592→      container.addChild(text);
   593→    });
   594→  }
   595→}
   596→
   597→export default ScheduleCanvas;
   598→

